import java.util.*;

class DisjointUnion {
    int[] parent;
    int[] rank;

    public DisjointUnion(int n) {
        parent = new int[n];
        rank = new int[n];

        Arrays.fill(parent, -1);
        Arrays.fill(rank, 1);
    }

    public int findParent(int node) {
        if (parent[node] == -1) return node;

        parent[node] = findParent(parent[node]); // path compression
        return parent[node];
    }

    public void unionByRank(int a, int b) {
        int parentA = findParent(a);
        int parentB = findParent(b);

        if (parentA == parentB) return;

        if (rank[parentA] > rank[parentB]) {
            parent[parentB] = parentA;
            rank[parentA] += rank[parentB];
        } else {
            parent[parentA] = parentB;
            rank[parentB] += rank[parentA];
        }
    }
}

class Solution {

    public int countCompleteComponents(int n, int[][] edges) {
        DisjointUnion dsu = new DisjointUnion(n);

        Map<Integer, Integer> componentParentToEdgesMap = new HashMap<>();

        // Step 1: Union components
        for (int[] edge : edges) {
            int u = edge[0], v = edge[1];
            dsu.unionByRank(u, v);
        }

        // Step 2: Count edges in each component
        for (int[] edge : edges) {
            int u = edge[0], v = edge[1];
            int parentU = dsu.findParent(u);

            componentParentToEdgesMap.put(parentU,
                    componentParentToEdgesMap.getOrDefault(parentU, 0) + 1);
        }

        // Step 3: Check complete components
        int res = 0;

        for (int i = 0; i < n; i++) {
            if (dsu.parent[i] == -1) { // root node
                int edgesCount = componentParentToEdgesMap.getOrDefault(i, 0);
                int nodes = dsu.rank[i];

                if (edgesCount == (nodes * (nodes - 1)) / 2) {
                    res++;
                }
            }
        }

        return res;
    }
}
